import { useEffect, useMemo, useRef, useState } from 'react';
import {
  Bell,
  CircleUserRound,
  Gift,
  House,
  LockKeyhole,
  MessageSquare,
  PlaySquare,
  ShieldCheck,
  Sparkles,
  Trophy,
  Wallet,
  X,
} from 'lucide-react';
import './App.css';
import {
  authenticate,
  closePayment,
  createPayment,
  getBackendConfig,
  getUserInfo,
  inquiryPayment,
} from './services/tokaApi';
import {
  extractAuthCodeFromBridgeResponse,
  getBridgeRuntimeInfo,
  isAlipayWebView,
  openPayment,
  requestAuthCode,
} from './lib/alipayBridge';

const SESSION_KEY = 'toka-ripple-session';

const USERS = [
  { id: 'u-1', name: 'Ana Sofia', rank: 1, streak: 24, points: 5200 },
