      const nextLiked = !post.liked;
      return {
        ...current,
        [postId]: {
          ...post,
          liked: nextLiked,
          likes: post.likes + (nextLiked ? 1 : -1),
        },
      };
    });
  }

  function toggleWallComments(postId) {
    setWallState((current) => ({
      ...current,
      [postId]: {
        ...current[postId],
        showComments: !current[postId]?.showComments,
      },
