              <div>
                <h3>Notificaciones</h3>
                <span>{notifications.length ? `${notifications.length} en el buzón` : 'Buzón vacío'}</span>
              </div>
              <button type="button" className="icon-btn" onClick={() => setShowNotifications(false)}>
                <X size={16} />
              </button>
            </div>

            <div className="overlay-actions">
              <button type="button" className="soft-btn" onClick={markAllNotificationsRead}>Marcar todas</button>
              <button type="button" className="soft-btn danger-soft" onClick={clearNotificationInbox}>Vaciar buzón</button>
            </div>

            <div className="stack-list notification-list">
              {notifications.length === 0 ? (
                <article className="empty-state">
                  <strong>No hay notificaciones</strong>
                  <p>Las actividades, el resumen tecnico y los eventos apareceran aqui.</p>
                </article>
              ) : (
                notifications.map((notif) => (
                  <article
                    key={notif.id}
                    className={`glass-card notification-card ${notif.read ? 'read' : 'unread'} ${notif.kind || ''}`}
                    onClick={() => setNotifications((current) => current.map((item) => (item.id === notif.id ? { ...item, read: true } : item)))}
                    role="button"
                    tabIndex={0}
                    onKeyDown={() => {}}
                  >
                    <div className="notification-head">
                      <h4>{notif.title}</h4>
                      <span className="notification-kind">{notif.kind === 'system' ? 'Resumen' : 'Evento'}</span>
                    </div>
                    <p>{notif.detail}</p>
                  </article>
                ))
              )}
            </div>
          </section>
        </div>
      ) : null}
    </main>
  );
}

export default App;
